import { Inference, Page } from "../../../v1/parsing/common/index.js";
import { InternationalIdV2Document } from "./internationalIdV2Document.js";
/**
 * International ID API version 2 inference prediction.
 */
export class InternationalIdV2 extends Inference {
    constructor(rawPrediction) {
        super(rawPrediction);
        /** The endpoint's name. */
        this.endpointName = "international_id";
        /** The endpoint's version. */
        this.endpointVersion = "2";
        /** The document's pages. */
        this.pages = [];
        this.prediction = new InternationalIdV2Document(rawPrediction["prediction"]);
        rawPrediction["pages"].forEach((page) => {
            if (page.prediction !== undefined && page.prediction !== null &&
                Object.keys(page.prediction).length > 0) {
                this.pages.push(new Page(InternationalIdV2Document, page, page["id"], page["orientation"]));
            }
        });
    }
}
